import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"How Developers Configure AI Coding Agents: An Empirical Study of Agentic AI Tool Configuration","description":"","frontmatter":{"title":"How Developers Configure AI Coding Agents: An Empirical Study of Agentic AI Tool Configuration","authors":"John Yang, Carlos E. Jimenez, Swetha Regunathan, Sanmi Koyejo, Ofir Press","published":"2026-02-16T00:00:00.000Z","source":"https://arxiv.org/abs/2602.14690"},"headers":[],"relativePath":"research/agent-harness/references/2026-02-16-configuring-agentic-coding-tools-2602-14690.md","filePath":"research/agent-harness/references/2026-02-16-configuring-agentic-coding-tools-2602-14690.md","lastUpdated":1779901665000}'),i={name:"research/agent-harness/references/2026-02-16-configuring-agentic-coding-tools-2602-14690.md"};function s(n,t,d,l,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="how-developers-configure-ai-coding-agents-an-empirical-study-of-agentic-ai-tool-configuration" tabindex="-1">How Developers Configure AI Coding Agents: An Empirical Study of Agentic AI Tool Configuration <a class="header-anchor" href="#how-developers-configure-ai-coding-agents-an-empirical-study-of-agentic-ai-tool-configuration" aria-label="Permalink to &quot;How Developers Configure AI Coding Agents: An Empirical Study of Agentic AI Tool Configuration&quot;">​</a></h1><p><strong>Authors</strong>: John Yang, Carlos E. Jimenez, Swetha Regunathan, Sanmi Koyejo, Ofir Press <strong>Published</strong>: February 16, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2602.14690" target="_blank" rel="noreferrer">https://arxiv.org/abs/2602.14690</a><strong>arXiv ID</strong>: 2602.14690 <strong>Categories</strong>: cs.SE, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The first large-scale empirical study of how developers configure agentic AI coding tools (Claude Code, OpenAI Codex CLI, Gemini CLI, Aider) in real-world repositories. Analyzes 2,926 GitHub repositories. Identifies 8 distinct configuration mechanisms, with CLAUDE.md (45.4%) and AGENTS.md (40.6%) as dominant context-file approaches. Claude Code users employ the broadest range of configuration mechanisms. 83.3% of &quot;Skills&quot; in the wild are static documentation, not dynamic executable flows.</p><hr><h2 id="dataset" tabindex="-1">Dataset <a class="header-anchor" href="#dataset" aria-label="Permalink to &quot;Dataset&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Repositories analyzed</td><td>2,926</td></tr><tr><td>Tools covered</td><td>Claude Code, OpenAI Codex CLI, Gemini CLI, Aider</td></tr><tr><td>Data source</td><td>GitHub public repositories</td></tr><tr><td>Analysis method</td><td>Static analysis of config files, commit history</td></tr></tbody></table><hr><h2 id="eight-configuration-mechanisms" tabindex="-1">Eight Configuration Mechanisms <a class="header-anchor" href="#eight-configuration-mechanisms" aria-label="Permalink to &quot;Eight Configuration Mechanisms&quot;">​</a></h2><p>The paper identifies and categorizes 8 distinct mechanisms developers use to configure agentic AI coding tools:</p><table tabindex="0"><thead><tr><th>#</th><th>Mechanism</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td>1</td><td><strong>Context Files</strong></td><td>Markdown files loaded into system prompt</td><td><code>CLAUDE.md</code>, <code>AGENTS.md</code>, <code>.cursorrules</code></td></tr><tr><td>2</td><td><strong>Skills / Commands</strong></td><td>Reusable procedural instructions</td><td><code>.claude/skills/</code>, custom slash commands</td></tr><tr><td>3</td><td><strong>Memory Files</strong></td><td>Persistent session state and history</td><td><code>MEMORY.md</code>, <code>.claude/memory/</code></td></tr><tr><td>4</td><td><strong>Rules Files</strong></td><td>Behavioral constraints and conventions</td><td><code>.claude/rules/</code>, <code>.clinerules</code></td></tr><tr><td>5</td><td><strong>MCP Servers</strong></td><td>External tool integrations via Model Context Protocol</td><td>GitHub MCP, filesystem MCP</td></tr><tr><td>6</td><td><strong>Hooks</strong></td><td>Event-triggered shell scripts</td><td>pre-commit hooks, stop hooks</td></tr><tr><td>7</td><td><strong>Permission Sets</strong></td><td>Tool allow/deny lists</td><td><code>allowedTools</code>, <code>deniedTools</code> in settings</td></tr><tr><td>8</td><td><strong>Environment Variables</strong></td><td>API keys, model selection, feature flags</td><td><code>ANTHROPIC_API_KEY</code>, <code>CLAUDE_MODEL</code></td></tr></tbody></table><hr><h2 id="adoption-rates-by-configuration-type" tabindex="-1">Adoption Rates by Configuration Type <a class="header-anchor" href="#adoption-rates-by-configuration-type" aria-label="Permalink to &quot;Adoption Rates by Configuration Type&quot;">​</a></h2><h3 id="context-files-most-adopted" tabindex="-1">Context Files (Most Adopted) <a class="header-anchor" href="#context-files-most-adopted" aria-label="Permalink to &quot;Context Files (Most Adopted)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Adoption Rate</th><th>Tool</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td><strong>45.4%</strong></td><td>Claude Code</td></tr><tr><td><strong>AGENTS.md</strong></td><td><strong>40.6%</strong></td><td>Cross-tool (emerging standard)</td></tr><tr><td><code>.cursorrules</code></td><td>~20%</td><td>Cursor</td></tr><tr><td><code>Aider conventions</code></td><td>~15%</td><td>Aider</td></tr></tbody></table><p><strong>Key finding</strong>: AGENTS.md is rapidly emerging as a <strong>cross-tool standard</strong> for agent configuration. Claude Code users who add AGENTS.md are optimizing for multi-tool compatibility.</p><h3 id="configuration-mechanism-breadth-by-tool" tabindex="-1">Configuration Mechanism Breadth by Tool <a class="header-anchor" href="#configuration-mechanism-breadth-by-tool" aria-label="Permalink to &quot;Configuration Mechanism Breadth by Tool&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Avg Mechanisms Used</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td><strong>Highest</strong> (uses broadest range)</td></tr><tr><td>OpenAI Codex CLI</td><td>Moderate</td></tr><tr><td>Gemini CLI</td><td>Lower</td></tr><tr><td>Aider</td><td>Lower</td></tr></tbody></table><hr><h2 id="skills-analysis-83-3-are-static-documentation" tabindex="-1">Skills Analysis: 83.3% Are Static Documentation <a class="header-anchor" href="#skills-analysis-83-3-are-static-documentation" aria-label="Permalink to &quot;Skills Analysis: 83.3% Are Static Documentation&quot;">​</a></h2><p>The paper finds a striking discrepancy between the theoretical capability of Skills (dynamic, executable flows with tool calls) and what developers actually build:</p><table tabindex="0"><thead><tr><th>Skill Type</th><th>Share</th></tr></thead><tbody><tr><td><strong>Static documentation only</strong></td><td><strong>83.3%</strong></td></tr><tr><td>Dynamic (with tool calls / conditional logic)</td><td>16.7%</td></tr></tbody></table><p><strong>Implication</strong>: Most developers treat Skills as structured markdown documentation rather than as executable agent procedures. The gap between potential and practice is large.</p><h3 id="common-static-skill-patterns" tabindex="-1">Common Static Skill Patterns <a class="header-anchor" href="#common-static-skill-patterns" aria-label="Permalink to &quot;Common Static Skill Patterns&quot;">​</a></h3><ul><li>Project architecture overviews</li><li>Coding style guides</li><li>API reference summaries</li><li>Domain-specific terminology definitions</li></ul><h3 id="rare-dynamic-skill-patterns" tabindex="-1">Rare Dynamic Skill Patterns <a class="header-anchor" href="#rare-dynamic-skill-patterns" aria-label="Permalink to &quot;Rare Dynamic Skill Patterns&quot;">​</a></h3><ul><li>Multi-step implementation workflows with verification steps</li><li>Automated test-generate-run loops</li><li>Context-aware code review flows</li></ul><hr><h2 id="claude-md-content-analysis" tabindex="-1">CLAUDE.md Content Analysis <a class="header-anchor" href="#claude-md-content-analysis" aria-label="Permalink to &quot;CLAUDE.md Content Analysis&quot;">​</a></h2><p>Across 2,926 repositories, CLAUDE.md files cluster around these content categories:</p><table tabindex="0"><thead><tr><th>Category</th><th>Prevalence</th></tr></thead><tbody><tr><td>Project structure / architecture overview</td><td>Very common</td></tr><tr><td>Coding conventions and style</td><td>Very common</td></tr><tr><td>Build and test commands</td><td>Common</td></tr><tr><td>Domain-specific constraints</td><td>Common</td></tr><tr><td>Behavioral rules (e.g., &quot;never use <code>git add -A</code>&quot;)</td><td>Moderate</td></tr><tr><td>Security constraints</td><td>Less common</td></tr><tr><td>Skill/command definitions</td><td>Less common</td></tr></tbody></table><hr><h2 id="agents-md-as-cross-tool-standard" tabindex="-1">AGENTS.md as Cross-Tool Standard <a class="header-anchor" href="#agents-md-as-cross-tool-standard" aria-label="Permalink to &quot;AGENTS.md as Cross-Tool Standard&quot;">​</a></h2><p>The rapid adoption of AGENTS.md (40.6%) suggests it is emerging as the dominant cross-tool agent configuration standard:</p><ul><li>Originally popularized by OpenAI Codex for cross-agent context sharing</li><li>Now adopted by Claude Code users seeking tool portability</li><li>Functions similarly to CLAUDE.md but recognized by multiple agent frameworks</li></ul><p><strong>Adoption trend</strong>: AGENTS.md adoption has grown faster than CLAUDE.md in newer repositories (post-2025), suggesting a market convergence toward cross-tool standards.</p><hr><h2 id="mcp-server-adoption" tabindex="-1">MCP Server Adoption <a class="header-anchor" href="#mcp-server-adoption" aria-label="Permalink to &quot;MCP Server Adoption&quot;">​</a></h2><p>MCP server configuration appears in a meaningful fraction of Claude Code repositories:</p><ul><li>Filesystem, GitHub, and web-search MCPs are most common</li><li>Custom internal MCP servers (e.g., company databases, proprietary APIs) appear in enterprise repositories</li><li>MCP adoption is significantly higher among Claude Code users than other tool users</li></ul><hr><h2 id="hooks-in-practice" tabindex="-1">Hooks in Practice <a class="header-anchor" href="#hooks-in-practice" aria-label="Permalink to &quot;Hooks in Practice&quot;">​</a></h2><p>Hooks (event-triggered shell scripts) are used by a notable minority:</p><table tabindex="0"><thead><tr><th>Hook Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Pre-commit</td><td>Lint checks, secret scanning before commit</td></tr><tr><td>Post-tool-use</td><td>Logging, metrics, audit trails</td></tr><tr><td>Stop hooks</td><td>Git status checks, uncommitted change alerts</td></tr><tr><td>Notification hooks</td><td>Slack/email notifications on completion</td></tr></tbody></table><hr><h2 id="recommendations-from-the-paper" tabindex="-1">Recommendations from the Paper <a class="header-anchor" href="#recommendations-from-the-paper" aria-label="Permalink to &quot;Recommendations from the Paper&quot;">​</a></h2><ol><li><strong>Context files are the primary configuration lever</strong> — invest in well-structured CLAUDE.md / AGENTS.md</li><li><strong>AGENTS.md for multi-tool compatibility</strong> — if using multiple agent frameworks, prefer AGENTS.md</li><li><strong>Elevate Skills from static docs to dynamic flows</strong> — the 83.3% static rate suggests untapped potential</li><li><strong>Claude Code&#39;s broad mechanism usage is a feature</strong> — power users get more leverage from hooks, MCP, rules, permissions</li></ol><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Validates and calibrates the workspace configuration approach:</p><ol><li><strong>CLAUDE.md 45.4% adoption is the most common pattern</strong>: Current workspace design (CLAUDE.md as primary config with @rules/ auto-loading) is empirically the most common approach.</li><li><strong>AGENTS.md 40.6% and rising</strong>: The workspace should maintain or add <code>AGENTS.md</code> as the cross-tool standard for sub-agents (existing AGENTS.md is confirmed best practice).</li><li><strong>83.3% static Skills gap</strong>: The workspace&#39;s dynamic Skills (with I/O contracts, tool calls, conditional routing) are rare in the wild — a genuine differentiator. The <code>research-hub</code>, <code>autoresearch</code>, and other skills with structured execution flows are in the top 16.7%.</li><li><strong>Claude Code users use broadest config range</strong>: Workspace&#39;s use of hooks (stop-hook-git-check.sh, user-prompt-submit.sh), MCP servers, rules, memory, and skills simultaneously is consistent with Claude Code power-user patterns.</li><li><strong>Hooks for git discipline</strong>: The stop hook pattern (alert on uncommitted changes) used in this workspace is an empirically validated practice.</li></ol>',52)])])}const u=e(i,[["render",s]]);export{m as __pageData,u as default};
